  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`log_id`),
  KEY `idx_user_actions` (`user_id`,`timestamp`),
  KEY `idx_table_record` (`table_name`,`record_id`,`timestamp`),
  KEY `idx_action_timestamp` (`action`,`timestamp`),
  KEY `idx_severity` (`severity`,`timestamp`),
  CONSTRAINT `fk_audit_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=526 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Comprehensive audit trail';


