  KEY `idx_document_flags` (`admissions_flag_status`,`finance_flag_status`,`status`),
  CONSTRAINT `fk_doc_submission_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
