  KEY `fk_fee_creator` (`created_by`),
  KEY `idx_program_year` (`program_name`,`academic_year`),
  KEY `idx_active_fees` (`is_active`,`effective_from`,`effective_to`),
  CONSTRAINT `fk_fee_creator` FOREIGN KEY (`created_by`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Fee structures for different programs';


-- Table: `finance_clearances`
DROP TABLE IF EXISTS `finance_clearances`;
CREATE TABLE `finance_clearances` (
  `clearance_id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `submission_id` bigint(20) unsigned NOT NULL,
  `verified_by_user_id` bigint(20) unsigned NOT NULL COMMENT 'Finance officer',
  `payment_reference` varchar(100) DEFAULT NULL,
  `payment_amount_verified` decimal(10,2) NOT NULL,
  `payment_date_verified` date NOT NULL,
  `required_amount` decimal(10,2) NOT NULL,
  `percentage_paid` decimal(5,2) GENERATED ALWAYS AS (`payment_amount_verified` / `required_amount` * 100) STORED,
  `finance_api_reference` varchar(255) DEFAULT NULL COMMENT 'External finance system reference',
  `finance_api_response` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'API response for audit' CHECK (json_valid(`finance_api_response`)),
  `is_cleared` tinyint(1) NOT NULL COMMENT 'TRUE = payment confirmed, FALSE = rejected',
  `clearance_notes` text DEFAULT NULL COMMENT 'Finance officer notes',
  `rejection_reason` text DEFAULT NULL COMMENT 'Required if not cleared',
  `manual_override` tinyint(1) DEFAULT 0,
  `override_reason` text DEFAULT NULL,
  `forwarded_to_admissions` tinyint(1) DEFAULT 0,
  `forwarded_at` timestamp NULL DEFAULT NULL,
  `verification_duration_seconds` int(10) unsigned DEFAULT NULL,
  `verified_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `is_pending` tinyint(1) NOT NULL DEFAULT 0,
  `pending_reason` text DEFAULT NULL,
  `partial_payment` tinyint(1) NOT NULL DEFAULT 0,
  `deferral_approved` tinyint(1) NOT NULL DEFAULT 0,
  `deferral_reason` text DEFAULT NULL,
  PRIMARY KEY (`clearance_id`),
  UNIQUE KEY `submission_id` (`submission_id`),
  KEY `idx_verified_by` (`verified_by_user_id`),
  KEY `idx_cleared` (`is_cleared`,`verified_at`),
  CONSTRAINT `fk_fin_clearance_submission` FOREIGN KEY (`submission_id`) REFERENCES `document_submissions` (`submission_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_fin_clearance_user` FOREIGN KEY (`verified_by_user_id`) REFERENCES `users` (`user_id`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Finance department payment clearance records';


