  UNIQUE KEY `uq_fx_rate_semester` (`intake_year`,`intake_semester`,`effective_from`),
  KEY `fk_fx_rate_published_by` (`published_by_user_id`),
  KEY `idx_fx_rate_active` (`intake_year`,`intake_semester`,`is_active`),
  CONSTRAINT `fk_fx_rate_published_by` FOREIGN KEY (`published_by_user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Finance-published semester exchange rates for USD payments';


-- Table: `sessions`
DROP TABLE IF EXISTS `sessions`;
CREATE TABLE `sessions` (
  `session_id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) unsigned NOT NULL,
  `session_token` varchar(255) NOT NULL COMMENT 'Secure session token',
  `refresh_token` varchar(255) DEFAULT NULL COMMENT 'JWT refresh token',
  `ip_address` varchar(45) NOT NULL,
  `user_agent` text DEFAULT NULL,
  `device_type` enum('desktop','mobile','tablet','other') DEFAULT 'other',
  `browser_name` varchar(100) DEFAULT NULL,
  `operating_system` varchar(100) DEFAULT NULL,
  `location_country` varchar(100) DEFAULT NULL,
  `location_city` varchar(100) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `last_activity` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `expires_at` datetime NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `terminated_at` timestamp NULL DEFAULT NULL,
  `termination_reason` enum('logout','timeout','forced','security') DEFAULT NULL,
  PRIMARY KEY (`session_id`),
  UNIQUE KEY `session_token` (`session_token`),
  UNIQUE KEY `refresh_token` (`refresh_token`),
  KEY `idx_user_sessions` (`user_id`,`is_active`,`last_activity`),
  KEY `idx_session_token` (`session_token`),
  KEY `idx_expiry` (`expires_at`,`is_active`),
  CONSTRAINT `fk_session_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='User session management';


-- Table: `student_profiles`
DROP TABLE IF EXISTS `student_profiles`;
CREATE TABLE `student_profiles` (
  `profile_id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) unsigned NOT NULL,
  `full_name` varchar(255) NOT NULL,
  `date_of_birth` date NOT NULL,
  `gender` enum('male','female','other','prefer_not_to_say') NOT NULL,
  `nationality` varchar(100) NOT NULL,
  `phone_number` varchar(20) NOT NULL,
  `alternative_phone` varchar(20) DEFAULT NULL,
  `address` text NOT NULL,
  `city` varchar(100) NOT NULL,
  `country` varchar(100) NOT NULL,
  `postal_code` varchar(20) DEFAULT NULL,
  `program` varchar(255) NOT NULL COMMENT 'Academic program enrolled',
  `faculty` varchar(255) NOT NULL,
  `department` varchar(255) NOT NULL,
  `intake_year` year(4) NOT NULL,
  `intake_semester` enum('semester_1','semester_2','semester_3') NOT NULL,
  `student_type` enum('undergraduate','postgraduate','diploma','certificate') NOT NULL,
  `study_mode` enum('full_time','part_time','distance','evening') NOT NULL DEFAULT 'full_time',
  `photo_path` varchar(500) DEFAULT NULL COMMENT 'Encrypted path to student photo',
  `emergency_contact_name` varchar(255) DEFAULT NULL,
  `emergency_contact_phone` varchar(20) DEFAULT NULL,
  `emergency_contact_relationship` varchar(100) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `registration_number` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`profile_id`),
  UNIQUE KEY `user_id` (`user_id`),
  UNIQUE KEY `registration_number` (`registration_number`),
  KEY `idx_program` (`program`),
  KEY `idx_intake` (`intake_year`,`intake_semester`),
  KEY `idx_full_name` (`full_name`),
  CONSTRAINT `fk_student_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Student personal and academic details';


-- Table: `system_settings`
DROP TABLE IF EXISTS `system_settings`;
CREATE TABLE `system_settings` (
  `setting_id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `setting_key` varchar(100) NOT NULL,
  `setting_value` text NOT NULL,
  `setting_type` enum('string','integer','boolean','json','date','email') NOT NULL,
  `setting_category` varchar(100) NOT NULL COMMENT 'e.g., email, sms, security, general',
  `description` text DEFAULT NULL,
  `is_editable` tinyint(1) DEFAULT 1 COMMENT 'Can be edited via admin panel',
  `is_sensitive` tinyint(1) DEFAULT 0 COMMENT 'Contains sensitive data (encrypt)',
  `validation_rules` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Validation rules for setting value' CHECK (json_valid(`validation_rules`)),
  `default_value` text DEFAULT NULL,
  `last_modified_by` bigint(20) unsigned DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`setting_id`),
  UNIQUE KEY `setting_key` (`setting_key`),
  KEY `fk_setting_modifier` (`last_modified_by`),
  KEY `idx_setting_category` (`setting_category`),
  KEY `idx_editable_settings` (`is_editable`,`setting_category`),
  CONSTRAINT `fk_setting_modifier` FOREIGN KEY (`last_modified_by`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='System configuration settings';


-- Table: `users`
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `user_id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `admission_number` varchar(50) NOT NULL COMMENT 'University admission number',
  `email` varchar(255) NOT NULL COMMENT 'User email address',
  `password_hash` varchar(255) NOT NULL COMMENT 'Bcrypt hashed password',
  `role` enum('student','finance_officer','registrar','admin') NOT NULL DEFAULT 'student',
  `mfa_enabled` tinyint(1) DEFAULT 0 COMMENT 'Multi-factor authentication status',
  `mfa_secret` varchar(255) DEFAULT NULL COMMENT 'TOTP secret for MFA',
  `email_verified_at` timestamp NULL DEFAULT NULL COMMENT 'Email verification timestamp',
  `last_login_at` timestamp NULL DEFAULT NULL COMMENT 'Last successful login',
  `login_attempts` tinyint(3) unsigned DEFAULT 0 COMMENT 'Failed login attempt counter',
  `locked_until` timestamp NULL DEFAULT NULL COMMENT 'Account lockout expiry time',
  `is_active` tinyint(1) DEFAULT 1 COMMENT 'Account active status',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`user_id`),
  UNIQUE KEY `admission_number` (`admission_number`),
  UNIQUE KEY `email` (`email`),
  KEY `idx_email` (`email`),
  KEY `idx_admission_number` (`admission_number`),
  KEY `idx_role` (`role`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='User authentication and authorization';


-- Table: `workflow_history`
DROP TABLE IF EXISTS `workflow_history`;
CREATE TABLE `workflow_history` (
  `history_id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `submission_id` bigint(20) unsigned NOT NULL,
  `from_status` varchar(50) DEFAULT NULL,
  `to_status` varchar(50) NOT NULL,
  `changed_by_user_id` bigint(20) unsigned DEFAULT NULL,
  `department` enum('student','admissions','finance','system') NOT NULL,
  `notes` text DEFAULT NULL,
  `changed_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`history_id`),
  KEY `fk_workflow_user` (`changed_by_user_id`),
  KEY `idx_submission_history` (`submission_id`,`changed_at`),
  CONSTRAINT `fk_workflow_submission` FOREIGN KEY (`submission_id`) REFERENCES `document_submissions` (`submission_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_workflow_user` FOREIGN KEY (`changed_by_user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=35 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Complete audit trail of workflow status changes';


SET FOREIGN_KEY_CHECKS=1;
